import{_ as a,o as i,c as e,a2 as n}from"./chunks/framework.D5wUhsuj.js";const k=JSON.parse('{"title":"Deploy a WordPress Site","description":"","frontmatter":{},"headers":[],"relativePath":"tutorials/deploy-wordpress.md","filePath":"tutorials/deploy-wordpress.md"}'),t={name:"tutorials/deploy-wordpress.md"};function l(r,s,p,o,d,h){return i(),e("div",null,[...s[0]||(s[0]=[n(`<h1 id="deploy-a-wordpress-site" tabindex="-1">Deploy a WordPress Site <a class="header-anchor" href="#deploy-a-wordpress-site" aria-label="Permalink to &quot;Deploy a WordPress Site&quot;">​</a></h1><p>AidiPanel can provision WordPress, its database, database user, configuration, and administrator account as one workflow.</p><h2 id="before-you-start" tabindex="-1">Before you start <a class="header-anchor" href="#before-you-start" aria-label="Permalink to &quot;Before you start&quot;">​</a></h2><ul><li>Install AidiPanel using the <a href="/docs/guide/installation">Installation guide</a>.</li><li>Point the domain&#39;s <code>A</code> record at the server.</li><li>Choose a unique WordPress administrator password.</li></ul><h2 id="_1-create-and-provision-wordpress" tabindex="-1">1. Create and provision WordPress <a class="header-anchor" href="#_1-create-and-provision-wordpress" aria-label="Permalink to &quot;1. Create and provision WordPress&quot;">​</a></h2><p>The panel provides the simplest workflow: open <strong>Sites → Add Site</strong>, select <strong>WordPress</strong>, and complete every required WordPress field.</p><p>The equivalent CLI command reads the password from stdin:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">printf</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;%s\\n&#39;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;StrongPassword123!&#39;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> |</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> site:add</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --type</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> wordpress</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --wp-title</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &#39;Example Site&#39;</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --wp-admin-user</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --wp-admin-pass-stdin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">  --wp-admin-email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin@example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br></div></div><p>Avoid placing a real password directly in the command because shell history and process inspection can expose it.</p><p>The workflow creates:</p><ul><li>the dedicated no-login Linux user <code>example</code>;</li><li><code>/home/example/htdocs/example.com</code>;</li><li>an isolated PHP-FPM pool;</li><li>the Nginx vhost;</li><li>WordPress files and <code>wp-config.php</code>;</li><li>a dedicated database and database user;</li><li>the initial administrator account.</li></ul><p>If provisioning fails, AidiPanel rolls back resources created by the incomplete WordPress transaction rather than leaving a half-installed site.</p><h2 id="_2-verify-dns-and-the-site" tabindex="-1">2. Verify DNS and the site <a class="header-anchor" href="#_2-verify-dns-and-the-site" aria-label="Permalink to &quot;2. Verify DNS and the site&quot;">​</a></h2><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">dig</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> +short</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Open <code>http://example.com</code> and sign in at <code>/wp-admin/</code>. New sites allow HTTP initially and use a temporary self-signed certificate for HTTPS until a trusted certificate is installed.</p><h2 id="_3-install-a-trusted-certificate" tabindex="-1">3. Install a trusted certificate <a class="header-anchor" href="#_3-install-a-trusted-certificate" aria-label="Permalink to &quot;3. Install a trusted certificate&quot;">​</a></h2><p>Once DNS returns the server&#39;s public IP:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ssl:install</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --email</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> admin@example.com</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>After the trusted certificate is active, enable force HTTPS and HSTS in the site&#39;s SSL tab when appropriate.</p><h2 id="_4-enable-cache-deliberately" tabindex="-1">4. Enable cache deliberately <a class="header-anchor" href="#_4-enable-cache-deliberately" aria-label="Permalink to &quot;4. Enable cache deliberately&quot;">​</a></h2><p>Page cache is off by default. For a public blog or brochure site:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sudo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> aidipanel</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> cache:enable</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --domain</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> example.com</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --install-nginx-helper</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><p>Check two anonymous requests:</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">curl</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -I</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> https://example.com/</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>The first cacheable request normally reports <code>MISS</code>; the next should report <code>HIT</code>. Logged-in sessions, administration paths, carts, checkout pages, query strings, and non-GET requests must bypass page cache.</p><div class="warning custom-block"><p class="custom-block-title">WooCommerce</p><p>Review <a href="/docs/tutorials/multi-php-woocommerce-cache">Multi-PHP &amp; WooCommerce Cache</a> before enabling page cache for a store. Never continue if logged-in, cart, or checkout requests report <code>HIT</code>.</p></div><h2 id="_5-configure-operations" tabindex="-1">5. Configure operations <a class="header-anchor" href="#_5-configure-operations" aria-label="Permalink to &quot;5. Configure operations&quot;">​</a></h2><p>The site detail page also provides:</p><ul><li>file management and archive operations;</li><li>databases and isolated phpMyAdmin sign-on;</li><li>WordPress real-cron management;</li><li>PHP version and runtime settings;</li><li>local backups and scheduled S3-compatible remote backups;</li><li>opt-in jailed SFTP;</li><li>Basic Auth, IP blocking, and Cloudflare-only origin access.</li></ul><h2 id="existing-wordpress-sites" tabindex="-1">Existing WordPress sites <a class="header-anchor" href="#existing-wordpress-sites" aria-label="Permalink to &quot;Existing WordPress sites&quot;">​</a></h2><p>Do not use the fresh WordPress provisioning flow when migrating an existing filesystem and database. Create a generic PHP site, transfer the existing files, import the database, then update <code>wp-config.php</code>. Follow <a href="/docs/tutorials/migrating-from-other-panels">Migrating from Another Panel</a>.</p>`,31)])])}const u=a(t,[["render",l]]);export{k as __pageData,u as default};
